var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"여기는 서윤! 방금 에너지 공급장치…… 로 보이는 헛간을 파괴했다!","JPN":"こちらアオイ・シズカ！　只今、エネルギー供給装置……と思われる納屋を破壊した！","ENG":"Seo Yoon here! I just destroyed… a barn that appears to be a power supply!","TWN":"這裡是徐芸！我已經破壞掉感覺像是動能補給裝置……的機房！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아카데미 쪽은 상황이 어때?","JPN":"アカデミー側の状況はどう？","ENG":"How about you Academy girls?","TWN":"學院那邊狀況如何？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"란체스터예요. 여기도 방금 막 에너지 공급장치로 추정되는……","JPN":"ランチェスターです。こちらもたった今、エネルギー供給装置と推定される……","ENG":"Lanchester here. We also destroyed a potential power supply…","TWN":"我是蘭賈斯特，我們剛才也已經破壞掉推測應該是動能補給裝置……"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"풍차를 철거했습니다.","JPN":"風車を撤去しました。","ENG":"…that looks like a windmill.","TWN":"的風車！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"느리네, 3류 용병. 이 나이엘님은 벌써 한참 전에 끝내버렸다고.","JPN":"遅いわね、三流傭兵。このナイエル様はとっくの前に終わらせてしまったわ。","ENG":"Too slow, too slow! I already finished ages ago.","TWN":"3流傭兵的動作真慢！奈爾我早就完成任務在一旁喝可樂聊天了好嗎！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"강철도 베어버리는 나의 천강역일섬 앞에 적 따위는…… ","JPN":"鋼鉄も斬り捨てる私の天剛逆日閃の前に敵なんか……","ENG":"My Starlight Inverse Strike can even cut through steel… ","TWN":"我的天剛！逆一閃！可是連鋼鐵都能砍斷，敵人算什…"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아얏!!","JPN":"痛ッ！","ENG":"Ouch!!","TWN":"哎呀！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_HIT_METAL"},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"싸우다가 갑자기 이상한 대사 하지 마!","JPN":"戦闘中に変なセリフ言わないでよ！","ENG":"Stop saying weird stuff in the middle of the fight!","TWN":"可以不要在戰鬥的時候說些莫名其妙的話嗎！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"파편에 머리나 맞고, 진짜!","JPN":"破片が頭に当たったし、もう！","ENG":"And watch out for the fragments!","TWN":"害我被碎片打到，都是你啦！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"치잇……!","JPN":"チッ……！","ENG":"Hmph…!","TWN":"嗟……！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그런데 이게 의미가 있어? 함선이랑 같은 구조니 했던 소리가 전부 네 착각일지도 모르잖아?","JPN":"でもこれって意味あるの？　艦船と同じ構造だとか全部あんたの勘違いかもしれないでしょ？","ENG":"What's the point of all this anyway? What if your theory about this being a ship is all hogwash?","TWN":"不過這樣真的行得通嗎？你剛才那推論也有可能是錯的吧？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그건……!","JPN":"そ、それは……！","ENG":"W-well…!","TWN":"我……！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"궁금하면 우리 에이스 카드한테 물어보면 되지.","JPN":"気になるなら、うちのエースに聞けばいいんだよ。","ENG":"We could always ask the ace up our sleeve.","TWN":"到底是對是錯問我們的王牌就知道啦！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"유미나, 들려? 어떻게 됐어?","JPN":"ミナ、聞こえる？　状況はどう？","ENG":"Can you hear me, Mina? How did it go?","TWN":"劉米娜，有聽到嗎？你那邊怎麼樣？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"성공이야! 방금 막 역장이 사라졌어!","JPN":"成功だよ！　ちょうど今力場が消えた！","ENG":"It worked! The force field just disappeared!","TWN":"成功了！剛才力場消失了！"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>좋아. 기다리지 말고 그대로 앞으로 달려.</color>","JPN":"<color=#ffd34c>よし。私たちのことはいいからそのまま向かって。</color>","ENG":"<color=#ffd34c>Great. Don't wait for us; just run straight through.</color>","TWN":"<color=#ffd34c>很好，那你還等什麼？還不衝進去！</color>"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 너희들은?","JPN":"待って、そっちはどうするの？","ENG":"But what about you guys?","TWN":"可是，那你們呢？"},"stage":{"bg":"CASTLE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이쪽은 환영인파가 몰려왔거든. 상대하는 데 시간이 좀 걸리겠어.","JPN":"侵食体の群れに歓迎されちゃってね。相手をするのにちょっと時間がかかりそう。","ENG":"We've got quite the welcome party here. It'll take a while to get rid of them.","TWN":"現在有一群傢伙出來迎接我，需要花點時間處理。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……이쪽도 마찬가지입니다.","JPN":"……こちらも同じです。","ENG":"…Same here.","TWN":"……我們這裡也一樣。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다행히 3종 침식체급은 보이지 않는군요.","JPN":"幸い第3種侵食体は見当たりません。","ENG":"Fortunately, I don't see anything that equals a Category 3.","TWN":"幸好看起來不像是3類侵蝕體。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"괜찮겠어? 하급 침식체도 수가 많으면 위험할 텐데……?","JPN":"大丈夫？　下級侵食体も数が多いと危ないかも……！","ENG":"Are you sure? It could still get dangerous if there're a lot of them…","TWN":"這樣可以嗎？就算是低階侵蝕體，但數量多的話也會有危險的……？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"걱정마세요. 미나 양만큼은 아니어도 저 역시 제 몸을 지킬 정도는 됩니다.","JPN":"ご心配なさらず。ミナさんほどではありませんが、私も自身を守る程度の力はあります。","ENG":"Don't worry. I may not be as capable as you, but I can handle myself.","TWN":"放心吧，雖然我們沒有米娜那麼厲害，但保護自己還是沒問題的。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 여기엔 나이엘 학생도 있으니까요.","JPN":"そしてここにはナイエルさんもいますから。","ENG":"Besides, I've also got Naielle with me.","TWN":"況且還有奈爾同學在呢。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그다지……. 믿음직스럽다고는 말하기 어렵습니다만.","JPN":"あまり……頼もしいとは言いにくいのですが。","ENG":"Although… I'm not sure if that's very reassuring.","TWN":"雖然……他的可靠度有待加強。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잠깐! 왜 어렵다는 건데?!","JPN":"ちょっと待って！　なんで言いにくいの！？","ENG":"Wait! What's that supposed to mean?","TWN":"喂喂！什麼叫可靠度有待加強？！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"죄송합니다. 학생들에 대한 믿음이 부족한 걸 보니 저도 아직 학생회장으로서 수양이 부족하군요.","JPN":"申し訳ありません。\\n生徒への信頼が足りないところは、\\n私もまだまだ生徒会長として修行が足りませんね。","ENG":"My apologies. Such lack of confidence in my fellow students demonstrates that I still have much to learn as Student President.","TWN":"抱歉，不小心說出我的心裡話，身為學生會長，我的言行必須再謹慎一點。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"좋아. 그럼 각자 침식체들을 따돌리는 거야.","JPN":"よし。じゃあ各自侵食体を引き離すのよ。","ENG":"All right, then. Everyone, keep those C.O.s on your tail.","TWN":"那大家各自把侵蝕體甩掉後，"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그 후에 역장 앞으로 집결해서…….","JPN":"その後は力場前に集結して……","ENG":"And then we'll assemble at the force field…","TWN":"一起到力場前集合……"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흐음. 나이도 어리면서 그럭저럭 지휘 흉내를 내는군.","JPN":"ふむ。若い割には指揮の真似が上手くできているじゃないか。","ENG":"Hmph. So you've managed to play the field commander, despite your youth.","TWN":"呵呵～明明就是個小鬼，還學起大人在那指揮，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CLAP"},{"id":"L1_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"평민 여성 주제에 제법이야.","JPN":"平民のくせになかなかだ。","ENG":"Not bad, for a peasant lass.","TWN":"而且還學得有模有樣的呢。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"큭……?!","JPN":"くっ……！？","ENG":"Ugh…?!","TWN":"唔……？！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이름도 밝히지 않고 창부터 던지다니…….","JPN":"名前も明かさず、いきなり槍を投げるとは……","ENG":"Tossing your lance without even introducing yourself?","TWN":"都還沒報上名來就先動刀動槍的……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이방인들의 야만스러움은 정말이지 어쩔 도리가 없군.","JPN":"異邦人の野蛮さは本当に仕方がないな。","ENG":"I must say these outsiders are simply too barbaric.","TWN":"外邦人野蠻的個性真是令人不敢恭維呢。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"뭐, 버릇없는 도둑고양이를 길들이는 재미도 있는 법이지.","JPN":"まあ、行儀の悪い泥棒猫を飼い慣らすのも面白いのだが。","ENG":"Well, I suppose it's always fun taming a stray cat.","TWN":"不過，馴服沒教養的野貓應該也滿有成就感的。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"여기는 서윤! 돌발사태 발생!","JPN":"こちらアオイ・シズカ！　非常事態発生！","ENG":"Seo Yoon here! We've got a contingency here!","TWN":"這裡是徐芸！突發狀況！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"최소 4종 이상, 전력 미상의 적이 등장했다!","JPN":"最低第4種以上、戦力不明の敵が現れた！","ENG":"An unknown enemy has appeared. This thing's at least a Category 4!","TWN":"出現至少4類以上，戰力不確定的敵人！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"학생회! 유미나! 내 말 듣고 있어?!","JPN":"生徒会！　ヤナギ・ミナ！　聞こえてる？","ENG":"Academy team! Yoo Mina! Does anyone copy?!","TWN":"學生會！劉米娜！你們有聽到嗎？！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"초조해하지 마라. 이방인. 네 친구들은 무사하니까.","JPN":"焦るな、異邦人。貴様のお友達は無事だ。","ENG":"Easy now, ye outsider. Thy friends are safe.","TWN":"別著急，你的朋友們沒事，"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나는 단지 우리 일을 도와 준 자네를 치하하러 왔을 뿐이다.","JPN":"私はただ、我々の計画に尽くした貴様を労いに来ただけだ。","ENG":"I'm simply here to commend thy efforts in aiding our task.","TWN":"你這樣幫我們，我是來稱讚你的。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"일을 도와 줬다고? 당신이 누군데?","JPN":"尽くしたですって？　あなたは誰？","ENG":"Aid you? Who the heck are you?","TWN":"我幫你們什麼？你又是誰？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"내 이름은 클라레스 엘 아르카데나.","JPN":"我が名はクラレス・エル・アルカデナ。","ENG":"I am Clareth El Arcadena.","TWN":"我叫克拉雷斯 耶魯 艾爾卡特納。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아르카데나 제국의 황태자이자 용검 라르고의 상속인이며, 유일하고도 정명한 인류의 지배자다.","JPN":"アルカデナ帝国の皇太子であり、\\n龍剣ラルゴの相続人であり、唯一かつ正当な人類の支配者である。","ENG":"The Crown Prince of the Empire of Arcadena, the heir to the Dragonsword Largo, and the sole and rightful ruler of all humankind.","TWN":"是艾爾卡特納帝國的皇太子，同時也是龍劍 雷諾可的繼承人，是唯一正統的人類支配者。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"황태자……?","JPN":"皇太子……？","ENG":"Crown Prince…?","TWN":"皇太子……？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다. 내가 이렇게 정식으로 소개하는 경우는 흔치 않지.","JPN":"そうだ。私がこうして名乗ることなど滅多にない。","ENG":"Aye. 'Tis not everyday when I introduce myself so formally.","TWN":"沒錯，我很少會這麼正式介紹自己的，"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"영광으로 알아라. 도둑고양이.","JPN":"光栄に思え、泥棒猫。","ENG":"Consider it an honor, ye stray cat.","TWN":"這可是你的榮幸，野貓。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그래? 황태자라는 분이 왜 이제 와서 행차하셨을까?","JPN":"そう？　皇太子ほどのお偉い方が、どうして今さらお出ましになったのかしら？","ENG":"Is that right? What took you so long, Your Highness?","TWN":"是喔？皇太子怎麼會現在才出巡呢？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"우릴 막으려면 전에도 기회가 많았을 텐데.","JPN":"私たちを止めるつもりなら、今までいくらでも機会があったはず。","ENG":"You could have stopped us a long time ago, if you really wanted.","TWN":"之前應該有很多機會可以阻止我們吧？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"말하지 않았나. 우리 일을 도와 줬다고.","JPN":"言っただろう。我々の計画に尽くしたと。","ENG":"I told you. You've aided us.","TWN":"我不是說了嗎？你們是在幫我們的忙。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"성역화를 통해 침식시켜도 그 <color=#ffd34c>현자</color> 놈이 만든 방주는 쉽게 통제할 수 있는 물건이 아니지.","JPN":"聖域化によって侵食させても、あの<color=#ffd34c>賢者</color>が作った箱舟は簡単に統制できる物ではない。","ENG":"Even with the sanctification to corrupt the Ark, the <color=#ffd34c>Sage's</color> creation is not so easy to control.","TWN":"就算藉由聖域化進行侵蝕，那個叫什麼<color=#ffd34c>智者</color>的，他所打造的方舟也不是輕易就能控制的。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"침식파에 대한 방호력이 너무 높아서 원래는 용인을 통해 처리할 계획이었지만…….","JPN":"侵食波に対する防護力が高すぎる故、本来は龍人を使って処理する計画だったが……","ENG":"The initial plan was to have the Dragonoid take care of it, due to its nearly impervious resistance to Corruption Rays…","TWN":"因為方舟對侵蝕波的防護力太高，本來是打算利用龍人來處理的……"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그걸 대신 파괴해 줬으니 감사할 일 아닌가?","JPN":"代わりに破壊してくれたのだから、ありがたいことだ。","ENG":"But now I have you to thank for destroying it on our behalf.","TWN":"結果你們替我們把它破壞掉了，這不是很感恩嗎？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"방주를 통제해? 설마……?","JPN":"箱舟を統制する？　まさか……？","ENG":"You want to control the Ark? No way…","TWN":"控制方舟？難道……？"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"보안 시스템이 잠시나마 무력화됐으니, 이 함선의 힘은 이제 내 손에 들어왔다.","JPN":"セキュリティシステムの一時的な無力化で、この艦船の力は今や私の手の中だ。","ENG":"With the security system down, albeit temporarily, this Ark is now in my hands.","TWN":"既然安全系統已經暫時失效，現在這艘艦船的力量成為我的囊中物。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"배우도, 무대도 모두 준비되었으니 이제 막을 열어야겠군.","JPN":"役者も舞台もすべて準備は整った。そろそろ幕を開けようじゃないか。","ENG":"Since the stage is set and all the actors are present, it is time to raise the curtains.","TWN":"演員和舞台都已經準備就緒，接下來該正式開演囉。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"명한다. 코핀 오브 네헤모트.","JPN":"コフィン・オブ・ネヘモトに命じる。","ENG":"I command thee. Coffin of Nehemoth.","TWN":"科芬之貝赫莫特聽命！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"성역화 지대에 공간 균열을 형성하라! 방해꾼들이 얼씬거리지 못하도록!","JPN":"聖域化地帯に空間亀裂を形成せよ！　邪魔者どもが近づけぬように！","ENG":"Create a spatial rift in the sanctified zone! Keep the intruders out!","TWN":"給我在聖域化地區形成空間裂縫！不准任何人來干擾！"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"무대에 설 수 있는 건 오직 배우들뿐.","JPN":"舞台に立つことができるのは役者のみ。","ENG":"Only the actors may stand upon the stage.","TWN":"能夠站上舞台的就只有演員而已，"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"관객들이 함부로 올라오게 두었다간 공연을 망칠 뿐이지.","JPN":"観客が勝手に舞台に上がるなど、公演を台無しにするだけだ。","ENG":"We wouldn't want any hecklers to interrupt the performance.","TWN":"觀眾隨便跑上台就只會破壞演出。"},"stage":{"bg":"CASTLE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};